const DB_KEY = 'fos_vehicle_app_v3';
const SESSION_KEY = 'fos_vehicle_session_v3';
const ROLES = {
  SUPER_ADMIN: 'SUPER_ADMIN',
  TENANT_ADMIN: 'TENANT_ADMIN',
  TENANT_VIEWER: 'TENANT_VIEWER'
};
const ROLE_LABELS = {
  SUPER_ADMIN: 'Super Admin',
  TENANT_ADMIN: 'Unit Admin',
  TENANT_VIEWER: 'Unit Viewer'
};
const SECTIONS = [
  {key:'general', title:'📋 General Information / البيانات العامة', icon:'📋'},
  {key:'driver', title:'🪪 Driver Check / فحص السائق', icon:'🪪'},
  {key:'exterior', title:'🚘 Vehicle Exterior / الفحص الخارجي', icon:'🚘'},
  {key:'lights', title:'💡 Lights & Signals / الأضواء والإشارات', icon:'💡'},
  {key:'interior', title:'🛞 Interior Check / الفحص الداخلي', icon:'🛞'},
  {key:'engine', title:'🛠️ Engine & Fluids / المحرك والسوائل', icon:'🛠️'},
  {key:'safety', title:'🧯 Safety Equipment / معدات السلامة', icon:'🧯'},
  {key:'oilfield', title:'🏗️ Oil Field Requirements / متطلبات الحقل', icon:'🏗️'},
  {key:'declaration', title:'✅ Final Declaration / الإقرار النهائي', icon:'✅'}
];
const EMBEDDED_LOGO = 'data:image/png;base64,';
const QUESTION_TYPES = [
  {value:'yes_no_na', label:'Yes / No / N/A'},
  {value:'text', label:'Text'},
  {value:'number', label:'Number'},
  {value:'date', label:'Date'}
];

const $ = (s,root=document)=>root.querySelector(s);
const $$ = (s,root=document)=>Array.from(root.querySelectorAll(s));
const byId = id => document.getElementById(id);
const uid = p => `${p}_${Math.random().toString(36).slice(2,8)}${Date.now().toString(36).slice(-4)}`;
const esc = v => String(v ?? '').replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]));
const fmtDate = v => v ? new Date(v).toLocaleDateString() : '';
const fmtDateTime = v => v ? new Date(v).toLocaleString() : '';

function defaultQuestionsFor(tenantId){
  const rows = [
    ['general','Inspection Date / تاريخ الفحص','date'],
    ['general','Time / الوقت','text'],
    ['general','Driver Name / اسم السائق','text'],
    ['general','Vehicle Number / رقم المركبة','text'],
    ['general','License Plate / رقم اللوحة','text'],
    ['general','Location / الموقع','text'],
    ['general','Odometer Reading / قراءة العداد','number'],
    ['driver','Valid driving license? / هل رخصة القيادة سارية؟','yes_no_na'],
    ['driver','Medically fit for driving? / هل السائق لائق صحياً؟','yes_no_na'],
    ['driver','Wearing required PPE? / هل يتم ارتداء معدات السلامة؟','yes_no_na'],
    ['exterior','Tires condition OK? / هل حالة الإطارات جيدة؟','yes_no_na'],
    ['exterior','Spare tire available? / هل يوجد إطار احتياطي؟','yes_no_na'],
    ['lights','Headlights working? / هل الأنوار الأمامية تعمل؟','yes_no_na'],
    ['lights','Brake lights working? / هل أنوار الفرامل تعمل؟','yes_no_na'],
    ['interior','Seat belts working? / هل أحزمة الأمان تعمل؟','yes_no_na'],
    ['interior','Horn working? / هل البوق يعمل؟','yes_no_na'],
    ['engine','Engine oil level OK? / هل مستوى زيت المحرك جيد؟','yes_no_na'],
    ['engine','Coolant level OK? / هل مستوى سائل التبريد جيد؟','yes_no_na'],
    ['safety','Fire extinguisher valid? / هل طفاية الحريق صالحة؟','yes_no_na'],
    ['safety','First aid kit available? / هل توجد حقيبة إسعافات أولية؟','yes_no_na'],
    ['oilfield','IVMS working? / هل نظام تتبع المركبة يعمل؟','yes_no_na'],
    ['oilfield','Vehicle authorized for site? / هل المركبة مصرح لها بالدخول؟','yes_no_na'],
    ['declaration','Vehicle safe to operate? / هل المركبة آمنة للتشغيل؟','yes_no_na'],
    ['declaration','Defects found / الأعطال المكتشفة','text'],
    ['declaration','Action required / الإجراء المطلوب','text']
  ];
  return rows.map(([sectionKey,label,type],i)=>({
    id: uid('q'), tenantId, sectionKey, label, type, required: i < 23, active: true
  }));
}

function cloneQuestionsForUnit(sourceQuestions, unitId){
  return (sourceQuestions || []).map(q => ({
    id: uid('q'),
    tenantId: unitId,
    sectionKey: q.sectionKey,
    label: q.label,
    type: q.type,
    required: !!q.required,
    active: q.active !== false
  }));
}

function defaultMasterQuestions(){
  return defaultQuestionsFor(null).map(q => ({...q, tenantId:null, isMaster:true}));
}

function seedDB(){
  if(localStorage.getItem(DB_KEY)) return;
  const tenant1 = {id:'t_fos', name:'FOS Energy LLC', code:'fos', active:true, createdAt:new Date().toISOString()};
  const tenant2 = {id:'t_demo', name:'Demo Operations', code:'demo', active:true, createdAt:new Date().toISOString()};
  const db = {
    tenants:[tenant1, tenant2],
    accounts:[
      {id:'a_super', tenantId:null, role:ROLES.SUPER_ADMIN, fullName:'System Super Admin', email:'admin@fos.local', password:'Admin@123', active:true},
      {id:'a_tenant', tenantId:'t_fos', role:ROLES.TENANT_ADMIN, fullName:'FOS Unit Admin', email:'unit@fos.local', password:'Unit@123', active:true},
      {id:'a_viewer', tenantId:'t_fos', role:ROLES.TENANT_VIEWER, fullName:'FOS Viewer', email:'viewer@fos.local', password:'Viewer@123', active:true}
    ],
    masterQuestions: defaultMasterQuestions(),
    questions:[...defaultQuestionsFor('t_fos'), ...defaultQuestionsFor('t_demo')],
    submissions:[]
  };
  localStorage.setItem(DB_KEY, JSON.stringify(db));
}
function getDB(){
  seedDB();
  const db = JSON.parse(localStorage.getItem(DB_KEY));
  if(!db.masterQuestions){ db.masterQuestions = defaultMasterQuestions(); saveDB(db); }
  return db;
}
function saveDB(db){ localStorage.setItem(DB_KEY, JSON.stringify(db)); }
function resetDB(){ localStorage.removeItem(DB_KEY); localStorage.removeItem(SESSION_KEY); seedDB(); }
function getSession(){ const raw=localStorage.getItem(SESSION_KEY); return raw?JSON.parse(raw):null; }
function setSession(a){ localStorage.setItem(SESSION_KEY, JSON.stringify(a)); }
function clearSession(){ localStorage.removeItem(SESSION_KEY); }
function findUnit(id){ return getDB().tenants.find(t=>t.id===id); }
function isAdminRole(role){ return role===ROLES.SUPER_ADMIN || role===ROLES.TENANT_ADMIN || role===ROLES.TENANT_VIEWER; }
function login(email,password){
  const db = getDB();
  const acc = db.accounts.find(a => a.email.toLowerCase()===email.toLowerCase() && a.password===password && a.active && isAdminRole(a.role));
  if(!acc) return {ok:false, msg:'Invalid username or password'};
  setSession(acc); return {ok:true, account:acc};
}
function requireSession(){
  const s = getSession();
  if(!s){ location.href='login.html'; return null; }
  return s;
}
function roleCanManageAccounts(role){ return role===ROLES.SUPER_ADMIN || role===ROLES.TENANT_ADMIN; }
function roleCanManageQuestions(role){ return role===ROLES.SUPER_ADMIN || role===ROLES.TENANT_ADMIN; }
function roleCanManageUnits(role){ return role===ROLES.SUPER_ADMIN; }

function renderTopbar(active=''){
  const session = getSession();
  const nav = [];
  nav.push(`<a class="nav-link secondary ${active==='home'?'active':''}" href="index.html">Home</a>`);
  nav.push(`<a class="nav-link journey" href="https://forms.office.com/r/EnX3KcBPhP?origin=lprLink" target="_blank" rel="noopener">Journey Issue</a>`);
  nav.push(`<a class="nav-link secondary ${active==='public'?'active':''}" href="public-form.html">Public Form</a>`);
  if(session){
    nav.push(`<a class="nav-link ${active==='dashboard'?'':'secondary'}" href="dashboard.html">Dashboard</a>`);
    nav.push(`<button class="nav-link accent" type="button" onclick="logout()">Logout</button>`);
  }else{
    nav.push(`<a class="nav-link ${active==='login'?'':'secondary'}" href="login.html">Admin Login</a>`);
  }
  return `<div class="topbar"><div class="container inner"><div class="brand"><img src="${EMBEDDED_LOGO}" alt="FOS logo"><div><h1>FOS Vehicle Inspection System</h1><p>Multi-unit inspection application</p></div></div><div class="nav-links">${nav.join('')}</div></div></div>`;
}
function mountTopbar(active){ byId('topbarMount').innerHTML = renderTopbar(active); }
function logout(){ clearSession(); location.href='login.html'; }

function initHome(){
  mountTopbar('home');
  seedDB();
}
function initLogin(){
  mountTopbar('login');
  if(getSession()) location.href='dashboard.html';
  byId('loginForm').addEventListener('submit', e=>{
    e.preventDefault();
    const res = login(byId('loginEmail').value.trim(), byId('loginPassword').value);
    byId('loginMsg').innerHTML = res.ok ? '' : `<div class="warning">${esc(res.msg)}</div>`;
    if(res.ok) location.href='dashboard.html';
  });
}

function scopeData(){
  const db = getDB();
  const s = getSession();
  const tenantId = s?.tenantId || null;
  return {
    db, s,
    tenants: s?.role===ROLES.SUPER_ADMIN ? db.tenants : db.tenants.filter(t=>t.id===tenantId),
    accounts: s?.role===ROLES.SUPER_ADMIN ? db.accounts : db.accounts.filter(a=>a.tenantId===tenantId),
    questions: s?.role===ROLES.SUPER_ADMIN ? db.questions : db.questions.filter(q=>q.tenantId===tenantId),
    masterQuestions: db.masterQuestions || [],
    submissions: s?.role===ROLES.SUPER_ADMIN ? db.submissions : db.submissions.filter(x=>x.tenantId===tenantId)
  };
}
function activateTab(name){
  $$('.tab-btn').forEach(b=>b.classList.toggle('active', b.dataset.tab===name));
  $$('.tab').forEach(t=>t.classList.toggle('active', t.id===`tab_${name}`));
}
function initDashboard(){
  mountTopbar('dashboard');
  const s = requireSession(); if(!s) return;
  byId('welcomeText').textContent = `Logged in as ${s.fullName} · ${ROLE_LABELS[s.role]}`;
  $$('.tab-btn').forEach(b=>b.addEventListener('click',()=>activateTab(b.dataset.tab)));
  activateTab('overview');
  bindDashboardActions();
  renderDashboard();
}
function renderDashboard(){
  const {s,tenants,accounts,questions,submissions} = scopeData();
  byId('kpis').innerHTML = `
    <div class="kpi info"><div>Total Submissions</div><div class="value">${submissions.length}</div><div class="meta">All submitted forms</div></div>
    <div class="kpi issue"><div>Issue Reports</div><div class="value">${submissions.filter(x=>x.status==='Issue').length}</div><div class="meta">At least one No answer</div></div>
    <div class="kpi safe"><div>Safe Reports</div><div class="value">${submissions.filter(x=>x.status==='Safe').length}</div><div class="meta">No issues detected</div></div>
    <div class="kpi warn"><div>Managed Items</div><div class="value">${tenants.length+accounts.length+questions.length}</div><div class="meta">Units, accounts, questions</div></div>`;
  renderUnits(); renderAccounts(); renderQuestions(); renderMasterQuestions(); renderSubmissions(); renderCharts(); populateSelectors();
  byId('tenantPanel').classList.toggle('hidden', !roleCanManageUnits(s.role));
  byId('accountsPanel').classList.toggle('hidden', !roleCanManageAccounts(s.role));
  byId('questionsPanel').classList.toggle('hidden', !roleCanManageQuestions(s.role));
  const tabUnits = document.querySelector('[data-tab="tenants"]'); if(tabUnits) tabUnits.classList.toggle('hidden', !roleCanManageUnits(s.role));
  const tabAccounts = document.querySelector('[data-tab="accounts"]'); if(tabAccounts) tabAccounts.classList.toggle('hidden', !roleCanManageAccounts(s.role));
  const tabQuestions = document.querySelector('[data-tab="questions"]'); if(tabQuestions) tabQuestions.classList.toggle('hidden', !roleCanManageQuestions(s.role));
  const tabMaster = document.querySelector('[data-tab="masterQuestions"]'); if(tabMaster) tabMaster.classList.toggle('hidden', s.role!==ROLES.SUPER_ADMIN);
}
function renderUnits(){
  const {tenants,s} = scopeData();
  byId('tenantRows').innerHTML = tenants.map(t=>`<tr><td>${esc(t.name)}</td><td><span class="code">${esc(t.code)}</span></td><td>${t.active?'Active':'Inactive'}</td><td>${fmtDate(t.createdAt)}</td><td>${roleCanManageUnits(s.role)?`<button class="btn small accent" onclick="removeUnit('${t.id}')">Delete</button>`:'-'}</td></tr>`).join('') || `<tr><td colspan="5" class="center">No units</td></tr>`;
}
function renderAccounts(){
  const {accounts,s} = scopeData();
  byId('accountRows').innerHTML = accounts.map(a=>`<tr><td>${esc(a.fullName)}</td><td>${esc(a.email)}</td><td>${ROLE_LABELS[a.role]||a.role}</td><td>${esc(findUnit(a.tenantId)?.name || 'All Units')}</td><td>${a.active?'Active':'Inactive'}</td><td><div class="actions"><button class="btn small secondary" onclick="editAccount('${a.id}')">Edit</button>${a.id!=='a_super'?`<button class="btn small accent" onclick="removeAccount('${a.id}')">Delete</button>`:''}</div></td></tr>`).join('') || `<tr><td colspan="6" class="center">No accounts</td></tr>`;
}
function renderQuestions(){
  const {questions} = scopeData();
  byId('questionRows').innerHTML = questions.map(q=>`<tr><td>${esc(findUnit(q.tenantId)?.name || '')}</td><td>${esc(SECTIONS.find(s=>s.key===q.sectionKey)?.title || q.sectionKey)}</td><td>${esc(q.label)}</td><td>${esc(QUESTION_TYPES.find(t=>t.value===q.type)?.label || q.type)}</td><td>${q.required?'Required':'Optional'}</td><td><div class="actions"><button class="btn small secondary" onclick="editQuestion('${q.id}')">Edit</button><button class="btn small accent" onclick="removeQuestion('${q.id}')">Delete</button></div></td></tr>`).join('') || `<tr><td colspan="6" class="center">No questions</td></tr>`;
}
function renderMasterQuestions(){
  const {s,masterQuestions} = scopeData();
  if(s.role !== ROLES.SUPER_ADMIN || !byId('masterQuestionRows')) return;
  byId('masterQuestionRows').innerHTML = masterQuestions.map(q=>`<tr><td>${esc(SECTIONS.find(sec=>sec.key===q.sectionKey)?.title || q.sectionKey)}</td><td>${esc(q.label)}</td><td>${esc(QUESTION_TYPES.find(t=>t.value===q.type)?.label || q.type)}</td><td>${q.required?'Required':'Optional'}</td><td><div class="actions"><button class="btn small secondary" onclick="editMasterQuestion('${q.id}')">Edit</button><button class="btn small accent" onclick="removeMasterQuestion('${q.id}')">Delete</button></div></td></tr>`).join('') || `<tr><td colspan="5" class="center">No global questions</td></tr>`;
}
function renderSubmissions(){
  const {submissions} = scopeData();
  byId('submissionRows').innerHTML = submissions.map(s=>`<tr><td><span class="code">${s.id}</span></td><td>${esc(s.tenantName)}</td><td>${esc(s.submitterName)}</td><td><span class="status ${s.status==='Safe'?'safe':'issue'}">${s.status}</span></td><td>${fmtDateTime(s.createdAt)}</td><td><div class="actions"><a class="btn small secondary" href="report.html?id=${encodeURIComponent(s.id)}" target="_blank">View</a><button class="btn small" onclick="downloadReport('${s.id}')">Download</button></div></td></tr>`).join('') || `<tr><td colspan="6" class="center">No submissions yet</td></tr>`;
}
function populateSelectors(){
  const {s,tenants} = scopeData();
  const tenantOptions = tenants.map(t=>`<option value="${t.id}">${esc(t.name)}</option>`).join('');
  if(byId('accountTenantId')) byId('accountTenantId').innerHTML = tenantOptions;
  if(byId('questionTenantId')) byId('questionTenantId').innerHTML = tenantOptions;
  if(byId('publicTenantLink')) byId('publicTenantLink').innerHTML = tenantOptions;
  if(byId('accountRole')){
    const roleList = [ROLES.SUPER_ADMIN, ROLES.TENANT_ADMIN, ROLES.TENANT_VIEWER].filter(r=>s.role===ROLES.SUPER_ADMIN || r!==ROLES.SUPER_ADMIN);
    byId('accountRole').innerHTML = roleList.map(r=>`<option value="${r}">${ROLE_LABELS[r]}</option>`).join('');
  }
  if(byId('questionSection')) byId('questionSection').innerHTML = SECTIONS.map(x=>`<option value="${x.key}">${esc(x.title)}</option>`).join('');
  if(byId('questionType')) byId('questionType').innerHTML = QUESTION_TYPES.map(x=>`<option value="${x.value}">${esc(x.label)}</option>`).join('');
  if(byId('masterQuestionSection')) byId('masterQuestionSection').innerHTML = SECTIONS.map(x=>`<option value="${x.key}">${esc(x.title)}</option>`).join('');
  if(byId('masterQuestionType')) byId('masterQuestionType').innerHTML = QUESTION_TYPES.map(x=>`<option value="${x.value}">${esc(x.label)}</option>`).join('');
  byId('accountTenantWrap').classList.toggle('hidden', s.role!==ROLES.SUPER_ADMIN);
  byId('questionTenantWrap').classList.toggle('hidden', s.role!==ROLES.SUPER_ADMIN);
}
function bindDashboardActions(){
  byId('tenantForm')?.addEventListener('submit', e=>{
    e.preventDefault();
    const db = getDB();
    const tenantId = uid('t');
    const name = byId('tenantName').value.trim(); const code = byId('tenantCode').value.trim();
    if(!name || !code) return alert('Enter unit name and code');
    db.tenants.push({id:tenantId,name,code,active:byId('tenantActive').value==='true',createdAt:new Date().toISOString()});
    db.questions.push(...cloneQuestionsForUnit(db.masterQuestions || defaultMasterQuestions(), tenantId));
    saveDB(db); e.target.reset(); renderDashboard();
  });
  byId('accountForm')?.addEventListener('submit', e=>{
    e.preventDefault();
    const {s} = scopeData();
    const db = getDB();
    const id = byId('accountId').value.trim();
    const role = byId('accountRole').value;
    let tenantId = s.role===ROLES.SUPER_ADMIN ? byId('accountTenantId').value : s.tenantId;
    if(role===ROLES.SUPER_ADMIN) tenantId = null;
    const rec = { id:id||uid('a'), tenantId, role, fullName:byId('accountFullName').value.trim(), email:byId('accountEmail').value.trim(), password:byId('accountPassword').value, active:byId('accountActive').value==='true' };
    if(!rec.fullName || !rec.email || !rec.password) return alert('Please complete all required account fields');
    const dup = db.accounts.find(a=>a.email.toLowerCase()===rec.email.toLowerCase() && a.id!==id);
    if(dup) return alert('Email already exists');
    if(id){ const idx = db.accounts.findIndex(a=>a.id===id); db.accounts[idx]=rec; } else db.accounts.push(rec);
    saveDB(db); e.target.reset(); byId('accountId').value=''; renderDashboard();
  });
  byId('questionForm')?.addEventListener('submit', e=>{
    e.preventDefault();
    const {s} = scopeData();
    const db = getDB();
    const id = byId('questionId').value.trim();
    const rec = { id:id||uid('q'), tenantId:s.role===ROLES.SUPER_ADMIN?byId('questionTenantId').value:s.tenantId, sectionKey:byId('questionSection').value, label:byId('questionLabel').value.trim(), type:byId('questionType').value, required:byId('questionRequired').value==='true', active:byId('questionActive').value==='true' };
    if(!rec.label) return alert('Please enter the question label');
    if(id){ const idx = db.questions.findIndex(q=>q.id===id); db.questions[idx]=rec; } else db.questions.push(rec);
    saveDB(db); e.target.reset(); byId('questionId').value=''; renderDashboard();
  });
  byId('masterQuestionForm')?.addEventListener('submit', e=>{
    e.preventDefault();
    const db = getDB();
    const id = byId('masterQuestionId').value.trim();
    const rec = { id:id||uid('mq'), tenantId:null, isMaster:true, sectionKey:byId('masterQuestionSection').value, label:byId('masterQuestionLabel').value.trim(), type:byId('masterQuestionType').value, required:byId('masterQuestionRequired').value==='true', active:byId('masterQuestionActive').value==='true' };
    if(!rec.label) return alert('Please enter the global question label');
    if(id){ const idx = db.masterQuestions.findIndex(q=>q.id===id); db.masterQuestions[idx]=rec; } else db.masterQuestions.push(rec);
    saveDB(db); e.target.reset(); byId('masterQuestionId').value=''; renderDashboard();
  });
  byId('syncQuestionsBtn')?.addEventListener('click', syncMasterQuestionsToAllUnits);
  byId('downloadAllBtn')?.addEventListener('click', exportAllCSV);
  byId('openPublicFormBtn')?.addEventListener('click', ()=>{ const tid = byId('publicTenantLink').value; location.href = `public-form.html?tenant=${encodeURIComponent(tid)}`; });
  byId('resetBtn')?.addEventListener('click', ()=>{ if(confirm('Reset demo database?')){ resetDB(); location.reload(); } });
}
function removeUnit(id){ if(!confirm('Delete unit and all related data?')) return; const db=getDB(); db.tenants=db.tenants.filter(t=>t.id!==id); db.accounts=db.accounts.filter(a=>a.tenantId!==id); db.questions=db.questions.filter(q=>q.tenantId!==id); db.submissions=db.submissions.filter(s=>s.tenantId!==id); saveDB(db); renderDashboard(); }
function removeAccount(id){ if(!confirm('Delete account?')) return; const db=getDB(); db.accounts=db.accounts.filter(a=>a.id!==id); saveDB(db); renderDashboard(); }
function removeQuestion(id){ if(!confirm('Delete question?')) return; const db=getDB(); db.questions=db.questions.filter(q=>q.id!==id); saveDB(db); renderDashboard(); }
function editAccount(id){ const a=getDB().accounts.find(x=>x.id===id); if(!a) return; byId('accountId').value=a.id; byId('accountFullName').value=a.fullName; byId('accountEmail').value=a.email; byId('accountPassword').value=a.password; byId('accountRole').value=a.role; if(byId('accountTenantId') && a.tenantId) byId('accountTenantId').value=a.tenantId; byId('accountActive').value=String(!!a.active); activateTab('accounts'); }
function editQuestion(id){ const q=getDB().questions.find(x=>x.id===id); if(!q) return; byId('questionId').value=q.id; byId('questionLabel').value=q.label; byId('questionSection').value=q.sectionKey; byId('questionType').value=q.type; byId('questionRequired').value=String(!!q.required); byId('questionActive').value=String(!!q.active); if(byId('questionTenantId')) byId('questionTenantId').value=q.tenantId; activateTab('questions'); }
function editMasterQuestion(id){ const q=getDB().masterQuestions.find(x=>x.id===id); if(!q) return; byId('masterQuestionId').value=q.id; byId('masterQuestionLabel').value=q.label; byId('masterQuestionSection').value=q.sectionKey; byId('masterQuestionType').value=q.type; byId('masterQuestionRequired').value=String(!!q.required); byId('masterQuestionActive').value=String(!!q.active); activateTab('masterQuestions'); }
function removeMasterQuestion(id){ if(!confirm('Delete global template question?')) return; const db=getDB(); db.masterQuestions=db.masterQuestions.filter(q=>q.id!==id); saveDB(db); renderDashboard(); }
function syncMasterQuestionsToAllUnits(){
  const db=getDB();
  if(!confirm('are u sure you want to change all qestions?')) return;
  const subsByUnit = new Map(db.submissions.map(s=>[s.tenantId,true]));
  db.questions = db.questions.filter(q => !db.tenants.some(t => t.id === q.tenantId));
  db.tenants.forEach(t => { db.questions.push(...cloneQuestionsForUnit(db.masterQuestions || [], t.id)); });
  saveDB(db); renderDashboard();
  alert('All unit questions have been synced from the global template.');
}

function drawBars(canvas, data, title){
  const ctx = canvas.getContext('2d'); const rect = canvas.getBoundingClientRect(); const ratio = window.devicePixelRatio||1;
  canvas.width = rect.width*ratio; canvas.height = rect.height*ratio; ctx.setTransform(ratio,0,0,ratio,0,0);
  const w=rect.width, h=rect.height; ctx.clearRect(0,0,w,h); ctx.fillStyle='#17324d'; ctx.font='700 16px Inter, sans-serif'; ctx.fillText(title,16,24);
  const max = Math.max(1,...data.map(x=>x.value)); const left=20, bottom=h-34, top=42, gap=18; const barW = Math.max(42,(w-left*2-gap*(data.length-1))/Math.max(data.length,1));
  data.forEach((d,i)=>{ const x=left+i*(barW+gap); const barH=(d.value/max)*(bottom-top-16); const y=bottom-barH; ctx.fillStyle=d.color; roundRect(ctx,x,y,barW,Math.max(8,barH),12,true,false); ctx.fillStyle='#17324d'; ctx.font='700 13px Inter, sans-serif'; ctx.fillText(String(d.value),x+8,y-8); ctx.fillStyle='#5d758c'; ctx.font='12px Inter, sans-serif'; ctx.fillText(d.label,x,h-10); });
}
function roundRect(ctx,x,y,w,h,r,fill,stroke){ctx.beginPath();ctx.moveTo(x+r,y);ctx.lineTo(x+w-r,y);ctx.quadraticCurveTo(x+w,y,x+w,y+r);ctx.lineTo(x+w,y+h-r);ctx.quadraticCurveTo(x+w,y+h,x+w-r,y+h);ctx.lineTo(x+r,y+h);ctx.quadraticCurveTo(x,y+h,x,y+h-r);ctx.lineTo(x,y+r);ctx.quadraticCurveTo(x,y,x+r,y);ctx.closePath();if(fill)ctx.fill();if(stroke)ctx.stroke();}
function renderCharts(){
  const {submissions} = scopeData();
  const safe = submissions.filter(x=>x.status==='Safe').length;
  const issue = submissions.filter(x=>x.status==='Issue').length;
  drawBars(byId('statusChart'), [{label:'Safe', value:safe, color:'#0f9d58'},{label:'Issue', value:issue, color:'#d93025'}], 'Submission Status');
  const map = {}; submissions.slice().reverse().forEach(s=>{ const k = new Date(s.createdAt).toLocaleDateString(); map[k]=(map[k]||0)+1; });
  const daily = Object.entries(map).slice(-7).map(([label,value])=>({label,value,color:'#0f7b6c'}));
  drawBars(byId('dailyChart'), daily.length?daily:[{label:'No Data',value:0,color:'#b3c4d7'}], 'Last 7 Days');
}

function activeQuestionsForUnit(tenantId){ return getDB().questions.filter(q=>q.tenantId===tenantId && q.active); }
function initPublicForm(){
  mountTopbar('public');
  const db = getDB();
  const select = byId('tenantSelect');
  select.innerHTML = db.tenants.filter(t=>t.active).map(t=>`<option value="${t.id}">${esc(t.name)}</option>`).join('');
  const qUnit = new URLSearchParams(location.search).get('tenant');
  if(qUnit && db.tenants.find(t=>t.id===qUnit)) select.value = qUnit;
  renderPublicSections(select.value);
  select.addEventListener('change', ()=>renderPublicSections(select.value));
  byId('publicForm').addEventListener('submit', submitPublicForm);
}
function renderPublicSections(tenantId){
  const qs = activeQuestionsForUnit(tenantId);
  const html = SECTIONS.map(sec=>({sec, items:qs.filter(q=>q.sectionKey===sec.key)})).filter(x=>x.items.length).map(({sec,items})=>`
    <div class="card section-card"><div class="section-head"><div class="section-icon">${sec.icon}</div><div class="section-title">${esc(sec.title)}</div></div>
      ${items.map(q=>renderQuestion(q)).join('')}
    </div>`).join('');
  byId('publicSections').innerHTML = html;
}
function renderQuestion(q){
  if(q.type==='yes_no_na') return `<div class="question-row" data-qid="${q.id}" data-type="${q.type}"><div class="q-label">${esc(q.label)} ${q.required?'<span style="color:var(--accent)">*</span>':''}</div><div class="answer-list"><button type="button" class="answer-chip" data-val="Y">Yes / نعم</button><button type="button" class="answer-chip" data-val="N">No / لا</button><button type="button" class="answer-chip" data-val="NA">N/A / لا ينطبق</button></div><div class="field" style="margin-top:12px"><label>Remark / ملاحظة</label><textarea class="remark" placeholder="Optional remark / ملاحظة اختيارية"></textarea></div></div>`;
  const type = q.type==='number'?'number':q.type==='date'?'date':'text';
  return `<div class="question-row" data-qid="${q.id}" data-type="${q.type}"><div class="q-label">${esc(q.label)} ${q.required?'<span style="color:var(--accent)">*</span>':''}</div><div class="field"><input class="value" type="${type}" placeholder="Enter value / أدخل القيمة"></div><div class="field"><label>Remark / ملاحظة</label><textarea class="remark" placeholder="Optional remark / ملاحظة اختيارية"></textarea></div></div>`;
}

document.addEventListener('click',e=>{
  const chip = e.target.closest('.answer-chip');
  if(!chip) return;
  const row = chip.closest('.question-row');
  $$('.answer-chip',row).forEach(x=>x.classList.remove('selected','y','n','na'));
  chip.classList.add('selected');
  chip.classList.add(chip.dataset.val==='Y'?'y':chip.dataset.val==='N'?'n':'na');
});

function submitPublicForm(e){
  e.preventDefault();
  const db = getDB();
  const tenantId = byId('tenantSelect').value;
  const tenant = findUnit(tenantId);
  const submitterName = byId('submitterName').value.trim();
  if(!submitterName) return alert('Please enter your name / يرجى إدخال الاسم');
  const questions = activeQuestionsForUnit(tenantId);
  const answers = {}; let noCount=0;
  for(const q of questions){
    const row = $(`.question-row[data-qid="${q.id}"]`);
    let value='';
    if(q.type==='yes_no_na') value = $('.answer-chip.selected',row)?.dataset.val || '';
    else value = $('.value',row)?.value?.trim() || '';
    const remark = $('.remark',row)?.value?.trim() || '';
    if(q.required && !value) return alert(`Please complete required question:\n${q.label}`);
    answers[q.id]=value; if(remark) answers[q.id+'__remark']=remark; if(value==='N') noCount++;
  }
  const submission = {id:uid('sub'), tenantId, tenantName:tenant?.name||'', submitterName, status:noCount>0?'Issue':'Safe', createdAt:new Date().toISOString(), answers};
  db.submissions.unshift(submission); saveDB(db);
  byId('publicMsg').innerHTML = `<div class="notice">Form submitted successfully / تم إرسال النموذج بنجاح. Reference: <span class="code">${submission.id}</span></div>`;
  byId('publicForm').reset(); renderPublicSections(tenantId);
}

function answerLabel(type,val){ if(type==='yes_no_na') return val==='Y'?'Yes / نعم':val==='N'?'No / لا':val==='NA'?'N/A / لا ينطبق':''; return val || ''; }
function reportHtml(sub){
  const qs = getDB().questions.filter(q=>q.tenantId===sub.tenantId && q.active);
  const sections = SECTIONS.map(sec=>({sec,items:qs.filter(q=>q.sectionKey===sec.key)})).filter(x=>x.items.length);
  return `<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>Inspection Report ${sub.id}</title><style>body{font-family:Inter,Segoe UI,Arial,sans-serif;background:#fff;color:#16324a;margin:0}.container{width:min(1180px,calc(100% - 32px));margin:0 auto;padding:24px 0}.report{background:#fff;border-radius:24px;padding:28px;border:1px solid #dbe6f1}.report-head{display:flex;justify-content:space-between;gap:18px;align-items:flex-start;padding-bottom:18px;border-bottom:2px solid #eaf0f6}.report-brand{display:flex;gap:14px;align-items:center}.report-brand img{width:74px;height:74px;object-fit:contain;border:1px solid #dbe6f1;border-radius:18px;padding:10px;background:#fff}.report h2{margin:0 0 6px}.report-grid{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:12px;margin:18px 0}.report-box{background:#f8fbfd;border:1px solid #dbe6f1;border-radius:16px;padding:14px}.report-box b{display:block;margin-bottom:6px}.table-wrap{overflow:auto;border:1px solid #dbe6f1;border-radius:18px;background:#fff}table{width:100%;border-collapse:collapse;min-width:900px}th,td{padding:14px 12px;border-bottom:1px solid #edf2f7;text-align:left;font-size:14px;vertical-align:top}th{background:#f9fbfd;color:#4d657a;font-size:12px;text-transform:uppercase;letter-spacing:.03em}.status{display:inline-flex;align-items:center;padding:7px 12px;border-radius:999px;font-size:12px;font-weight:800}.status.safe{background:#eaf8ef;color:#166a3a}.status.issue{background:#fff0f0;color:#a12c2c}.code{font-family:ui-monospace,SFMono-Regular,Menlo,monospace;background:#f4f7fa;padding:3px 8px;border-radius:8px}.footer-note{margin-top:18px;padding-top:12px;border-top:1px dashed #d9e4ef;color:#62809a;font-size:12px}@media print{body{background:#fff}.container{width:100%;margin:0;padding:0}.report{border:none;padding:0;border-radius:0}}@media (max-width:980px){.report-grid{grid-template-columns:1fr}}@media (max-width:768px){.container{width:min(100%,calc(100% - 20px));padding:14px 0}.report{padding:18px;border-radius:18px}.report-head{flex-direction:column;align-items:flex-start}.report-brand img{width:62px;height:62px}table{min-width:640px}th,td{padding:11px 10px;font-size:13px}}@media (max-width:480px){.container{width:min(100%,calc(100% - 16px))}.report{padding:14px}.report h2{font-size:22px}table{min-width:560px}}</style></head><body><div class="container page"><div class="report"><div class="report-head"><div class="report-brand"><img src="${EMBEDDED_LOGO}" alt="FOS logo"><div><h2>Daily Vehicle Inspection Report</h2><div style="color:var(--muted)">${esc(sub.tenantName)} · Professional branded output</div></div></div><div><div><b>Reference</b></div><div class="code">${sub.id}</div></div></div><div class="report-grid"><div class="report-box"><b>Unit</b>${esc(sub.tenantName)}</div><div class="report-box"><b>Submitted By</b>${esc(sub.submitterName)}</div><div class="report-box"><b>Status</b><span class="status ${sub.status==='Safe'?'safe':'issue'}">${sub.status}</span></div><div class="report-box"><b>Date & Time</b>${fmtDateTime(sub.createdAt)}</div></div>${sections.map(({sec,items})=>`<div class="report-section"><h3>${esc(sec.title)}</h3><div class="table-wrap"><table><thead><tr><th>Question</th><th>Answer</th><th>Remark</th></tr></thead><tbody>${items.map(q=>`<tr><td>${esc(q.label)}</td><td>${esc(answerLabel(q.type, sub.answers[q.id]))}</td><td>${esc(sub.answers[q.id+'__remark']||'')}</td></tr>`).join('')}</tbody></table></div></div>`).join('')}<div class="footer-note">Generated by FOS Vehicle Inspection System</div></div></div></body></html>`;
}
function downloadReport(id){ const sub = getDB().submissions.find(x=>x.id===id); if(!sub) return; const blob = new Blob([reportHtml(sub)], {type:'text/html;charset=utf-8'}); const a=document.createElement('a'); a.href=URL.createObjectURL(blob); a.download=`inspection_report_${id}.html`; a.click(); setTimeout(()=>URL.revokeObjectURL(a.href),1000); }
function exportAllCSV(){ const {submissions} = scopeData(); const csv = [['Submission ID','Unit','Submitter','Status','Created At'],...submissions.map(s=>[s.id,s.tenantName,s.submitterName,s.status,s.createdAt])].map(r=>r.map(v=>`"${String(v??'').replace(/"/g,'""')}"`).join(',')).join('\n'); const a=document.createElement('a'); a.href=URL.createObjectURL(new Blob([csv],{type:'text/csv;charset=utf-8'})); a.download='all_submissions.csv'; a.click(); setTimeout(()=>URL.revokeObjectURL(a.href),1000); }
function initReport(){ mountTopbar(); const id = new URLSearchParams(location.search).get('id'); const sub = getDB().submissions.find(x=>x.id===id); if(!sub){ byId('reportMount').innerHTML = '<div class="warning">Report not found.</div>'; return; } byId('reportMount').innerHTML = reportHtml(sub).match(/<body>([\s\S]*)<\/body>/i)[1]; }

window.initHome = initHome; window.initLogin = initLogin; window.initDashboard = initDashboard; window.initPublicForm = initPublicForm; window.initReport = initReport;
window.logout = logout; window.removeUnit = removeUnit; window.removeAccount = removeAccount; window.removeQuestion = removeQuestion; window.editAccount = editAccount; window.editQuestion = editQuestion; window.editMasterQuestion = editMasterQuestion; window.removeMasterQuestion = removeMasterQuestion; window.syncMasterQuestionsToAllUnits = syncMasterQuestionsToAllUnits; window.downloadReport = downloadReport; window.resetDB = resetDB;
seedDB();
